features.snippet:
interface my_intf;
  logic valid;
  logic [7:0] data;
endinterface

interface bus_intf;
  logic req;
  logic ack;
endinterface

module top;
  bus_intf b();
  initial begin
    b.req = 1'b1;
  end
endmodule

interface simple_if;
  logic clk;
  logic data;
endinterface

module consumer(simple_if s);
  always_ff @(posedge s.clk) begin
    s.data <= 1'b0;
  end
endmodule
